#include <stdio.h>
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int count = 0;
        int denominations[] = {100, 50, 10, 5, 2, 1};
        for (int i = 0; i < 6; i++) {
            while (N >= denominations[i]) {
                N -= denominations[i];
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

